import{_ as a,o as i,c as o,ag as s}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Parpadeo","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-quality/flicker.md","filePath":"es/power-quality/flicker.md"}'),l={name:"es/power-quality/flicker.md"};function n(r,e,c,t,d,p){return i(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="parpadeo" tabindex="-1">Parpadeo <a class="header-anchor" href="#parpadeo" aria-label="Permalink to &quot;Parpadeo&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>El parpadeo es una fluctuación visible en la intensidad de la iluminación causada por cambios rápidos en el voltaje.</p><p>Es un problema de calidad de energía que afecta la percepción humana y puede indicar inestabilidad en el sistema eléctrico.</p><p>El parpadeo se asocia típicamente con cargas repetitivas o fluctuantes que provocan variaciones de voltaje pequeñas pero frecuentes.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>Comprender el parpadeo es importante para:</p><ul><li>Mantener condiciones de iluminación aceptables para el personal</li><li>Prevenir molestias y fatiga visual</li><li>Identificar comportamiento inestable de las cargas en el sistema</li><li>Mejorar la calidad de energía general</li></ul><p>Incluso pequeñas variaciones de voltaje pueden volverse perceptibles cuando ocurren de forma repetida.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>El parpadeo ocurre cuando el voltaje fluctúa con el tiempo debido a la demanda variable de corriente.</p><p>Estas fluctuaciones provocan cambios correspondientes en la salida de luz, especialmente en sistemas de iluminación sensibles a las variaciones de voltaje.</p><p>Las fuentes comunes incluyen:</p><ul><li>Equipos con cargas que cambian rápidamente</li><li>Arranque y parada de motores de gran tamaño</li><li>Hornos de arco y equipos de soldadura</li><li>Procesos industriales cíclicos</li></ul><p>La severidad del parpadeo depende de:</p><ul><li>Magnitud de la variación de voltaje</li><li>Frecuencia de las fluctuaciones</li><li>Sensibilidad del sistema de iluminación</li></ul><p>La percepción humana desempeña un papel clave en cómo se experimenta el parpadeo.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Las consideraciones sobre parpadeo son importantes en:</p><ul><li>Plantas industriales con cargas fluctuantes</li><li>Instalaciones con requisitos de iluminación sensibles</li><li>Áreas donde el personal está presente de forma continua</li><li>Instalaciones con ciclos de arranque de motores de gran tamaño</li><li>Sistemas con procesos de soldadura o calentamiento</li></ul><p>Es relevante dondequiera que las variaciones de voltaje afecten la iluminación visible.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Nivel de variación de voltaje</strong><br> Variaciones mayores incrementan la severidad del parpadeo</p></li><li><p><strong>Frecuencia de fluctuación</strong><br> Ciertas frecuencias son más perceptibles para el ojo humano</p></li><li><p><strong>Comportamiento de la carga</strong><br> Cambios rápidos y repetitivos generan un parpadeo más visible</p></li><li><p><strong>Tipo de iluminación</strong><br> Algunas tecnologías de iluminación son más sensibles que otras</p></li><li><p><strong>Robustez del sistema</strong><br> Los sistemas más robustos experimentan fluctuaciones de voltaje menores</p></li><li><p><strong>Métodos de mitigación</strong><br> El diseño del equipo y del sistema puede reducir el impacto del parpadeo</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>El parpadeo suele ser más perceptible que otros problemas de calidad de energía</li><li>Las cargas fluctuantes de gran tamaño son la causa principal en sistemas industriales</li><li>La iluminación LED y electrónica puede responder de forma diferente a los cambios de voltaje</li><li>Separar los circuitos de iluminación sensibles de las cargas pesadas reduce el impacto</li><li>El monitoreo ayuda a identificar fuentes y patrones de parpadeo</li></ul>',25)])])}const b=a(l,[["render",n]]);export{m as __pageData,b as default};
